    35→// Escape codes for colorizing output.
    36→const (
    37→	Reset  = "\033[0m"
    38→	Red    = "\033[31m"
    39→	Green  = "\033[32m"
    40→	Yellow = "\033[33m"
    41→	Blue   = "\033[34m"
    42→	Purple = "\033[35m"
    43→	Cyan   = "\033[36m"
    44→	Gray   = "\033[37m"
    45→	White  = "\033[97m"
