    13→// SequentialTests contains all sequential correctness tests
    14→type SequentialTests struct {
    15→	harness *TestHarness
    16→	t       *testing.T
    17→}
    18→
    19→// NewSequentialTests creates a new sequential test suite
    20→func NewSequentialTests(harness *TestHarness, t *testing.T) *SequentialTests {
    21→	return &SequentialTests{harness: harness, t: t}
    22→}
    23→
    24→// RunAll runs all sequential tests
    25→func (s *SequentialTests) RunAll() []TestResult {
    26→	var results []TestResult
    27→
    28→	tests := []struct {
    29→		name string
    30→		fn   func() error
    31→	}{
    32→		{"CreateDatabase", s.TestCreateDatabase},
    33→		{"GetDatabase", s.TestGetDatabase},
    34→		{"DeleteDatabase", s.TestDeleteDatabase},
    35→		{"PutDocument", s.TestPutDocument},
    36→		{"PutDocumentOverwrite", s.TestPutDocumentOverwrite},
    37→		{"GetDocument", s.TestGetDocument},
    38→		{"DeleteDocument", s.TestDeleteDocument},
    39→		{"GetCollection", s.TestGetCollection},
    40→		{"GetCollectionWithInterval", s.TestGetCollectionWithInterval},
    41→		{"NestedDocumentsAndCollections", s.TestNestedDocumentsAndCollections},
    42→		{"PostDocument", s.TestPostDocument},
    43→		{"PatchArrayAdd", s.TestPatchArrayAdd},
    44→		{"PatchObjectAdd", s.TestPatchObjectAdd},
    45→		{"OptionsDatabase", s.TestOptionsDatabase},
    46→		{"PathPercentEncoding", s.TestPathPercentEncoding},
    47→		{"DocumentSchemaValidation", s.TestDocumentSchemaValidation},
    48→		{"ErrorResponseFormat", s.TestErrorResponseFormat},
    49→	}
    50→
    51→	for _, test := range tests {
    52→		start := time.Now()
    53→		err := test.fn()
    54→		duration := time.Since(start)
    55→
    56→		result := TestResult{
    57→			Name:     test.name,
    58→			Passed:   err == nil,
    59→			Duration: duration,
    60→		}
    61→		if err != nil {
    62→			result.Error = err.Error()
    63→		}
    64→		results = append(results, result)
    65→
    66→		if s.t != nil {
    67→			if err != nil {
    68→				s.t.Errorf("%s: %v", test.name, err)
    69→			} else {
    70→				s.t.Logf("%s: PASSED (%v)", test.name, duration)
    71→			}
    72→		}
    73→	}
    74→
    75→	return results
    76→}
