    65→// StartServer starts the OwlDB server
    66→func (h *TestHarness) StartServer(ctx context.Context) error {
    67→	h.mu.Lock()
    68→	defer h.mu.Unlock()
    69→
    70→	args := []string{
    71→		"-p", fmt.Sprintf("%d", h.Port),
    72→		"-s", h.SchemaFile,
    73→	}
    74→	if h.TokenFile != "" {
    75→		args = append(args, "-t", h.TokenFile)
    76→	}
    77→
    78→	h.ServerCmd = exec.CommandContext(ctx, h.ServerBinary, args...)
    79→	h.ServerCmd.Stdout = os.Stdout
    80→	h.ServerCmd.Stderr = os.Stderr
    81→
    82→	if err := h.ServerCmd.Start(); err != nil {
    83→		return fmt.Errorf("failed to start server: %w", err)
