   106→	h.mu.Lock()
   107→	defer h.mu.Unlock()
   108→
   109→	if h.ServerCmd != nil && h.ServerCmd.Process != nil {
   110→		if err := h.ServerCmd.Process.Signal(os.Interrupt); err != nil {
   111→			return h.ServerCmd.Process.Kill()
   112→		}
   113→		h.ServerCmd.Wait()
   114→	}
   115→	return nil
