    81→func (i *IntegrationTests) TestPostDocumentReturnsURI() error {
    82→	dbName := GenerateTestDBName()
    83→	defer i.harness.DeleteDatabase(dbName)
    84→
    85→	if err := i.harness.CreateDatabase(dbName); err != nil {
    86→		return err
