   128→func (i *IntegrationTests) TestPostDocumentCreatesDocument() error {
   129→	dbName := GenerateTestDBName()
   130→	defer i.harness.DeleteDatabase(dbName)
   131→
   132→	if err := i.harness.CreateDatabase(dbName); err != nil {
   133→		return err
   134→	}
   135→
   136→	doc := map[string]interface{}{"data": "posted"}
   137→	resp, err := i.harness.HTTPRequest("POST", "/v1/"+dbName+"/", doc)
   138→	if err != nil {
   139→		return err
   140→	}
   141→
   142→	// POST is optional
   143→	if resp.StatusCode == http.StatusMethodNotAllowed {
   144→		return nil
   145→	}
   146→
   147→	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
   148→		return fmt.Errorf("POST failed with status %d", resp.StatusCode)
   149→	}
   150→
   151→	result, err := resp.JSON()
   152→	if err != nil {
   153→		return err
   154→	}
   155→
   156→	// Extract the document path from response.
   157→	// The server may return a stripped path (without /v1/<dbname> prefix per P2 spec)
   158→	// or a full path. We need to construct <dbname>/<docname> for retrieval.
   159→	var docPath string
   160→	if uri, ok := result["uri"].(string); ok {
   161→		stripped := strings.TrimPrefix(uri, "/v1/")
   162→		// If the path still contains the dbName, use it as-is
   163→		if strings.HasPrefix(stripped, dbName) {
   164→			docPath = stripped
   165→		} else {
   166→			// Stripped path: prepend dbName
   167→			docPath = dbName + "/" + strings.TrimPrefix(stripped, "/")
   168→		}
   169→	} else if path, ok := result["path"].(string); ok {
   170→		stripped := strings.TrimPrefix(path, "/v1/")
   171→		if strings.HasPrefix(stripped, dbName) {
   172→			docPath = stripped
   173→		} else {
   174→			docPath = dbName + "/" + strings.TrimPrefix(stripped, "/")
   175→		}
   176→	} else {
   177→		return fmt.Errorf("no path returned")
   178→	}
   179→
   180→	// Verify document was created
   181→	retrievedDoc, err := i.harness.GetDocument(docPath)
   182→	if err != nil {
   183→		return fmt.Errorf("failed to retrieve POSTed document: %w", err)
   184→	}
   185→
   186→	docData, ok := retrievedDoc["doc"].(map[string]interface{})
   187→	if !ok {
   188→		docData = retrievedDoc
   189→	}
   190→
   191→	if docData["data"] != "posted" {
   192→		return fmt.Errorf("document content mismatch")
   193→	}
   194→
   195→	return nil
   196→}
