// Package skiplist provides a concurrent skip list implementation using
// lazy synchronization and atomic operations.
package skiplist

import (
	"cmp"
	"context"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 16
const pFactor = 0.5

// UpdateCheck is a function called by Upsert to determine the new value.
// It receives the key, the current value (or zero value if not exists), and
// whether the key currently exists in the list.
// If it returns an error, the upsert is not performed.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair holds a key-value pair returned from Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// node is a single node in the skip list.
type node[K cmp.Ordered, V any] struct {
	key      K
	value    V
	mu       sync.Mutex
	marked   atomic.Bool // true if logically deleted
	topLevel int
	next     [maxLevel]*node[K, V]
	isHead   bool
	isTail   bool
}

// SkipList is a concurrent skip list.
type SkipList[K cmp.Ordered, V any] struct {
	head     *node[K, V]
	tail     *node[K, V]
	topLevel int
	mu       sync.Mutex // protects topLevel
}

// New creates a new empty SkipList.
func New[K cmp.Ordered, V any]() *SkipList[K, V] {
	var zeroK K
	head := &node[K, V]{
		key:      zeroK,
		topLevel: maxLevel - 1,
		isHead:   true,
	}
	tail := &node[K, V]{
		key:      zeroK,
		topLevel: maxLevel - 1,
		isTail:   true,
	}
	for i := 0; i < maxLevel; i++ {
		head.next[i] = tail
	}
	return &SkipList[K, V]{
		head:     head,
		tail:     tail,
		topLevel: 0,
	}
}

// nodeLessKey returns true if node n's key is less than key.
func (sl *SkipList[K, V]) nodeLessKey(n *node[K, V], key K) bool {
	if n.isHead {
		return true
	}
	if n.isTail {
		return false
	}
	return n.key < key
}

// nodeKeyIs returns true if node n's key equals key.
func nodeKeyIs[K cmp.Ordered, V any](n *node[K, V], key K) bool {
	return !n.isHead && !n.isTail && n.key == key
}

// randomLevel generates a random level for a new node.
func randomLevel() int {
	level := 0
	for level < maxLevel-1 && rand.Float64() < pFactor {
		level++
	}
	return level
}

// find returns predecessors and successors at each level for the given key.
// This operation is lock-free (does not acquire locks).
func (sl *SkipList[K, V]) find(key K) (preds [maxLevel]*node[K, V], succs [maxLevel]*node[K, V]) {
	sl.mu.Lock()
	topLevel := sl.topLevel
	sl.mu.Unlock()

	pred := sl.head
	for level := topLevel; level >= 0; level-- {
		curr := pred.next[level]
		for sl.nodeLessKey(curr, key) {
			pred = curr
			curr = pred.next[level]
		}
		preds[level] = pred
		succs[level] = curr
	}
	// Fill in higher levels (not traversed) with head/tail
	for level := topLevel + 1; level < maxLevel; level++ {
		preds[level] = sl.head
		succs[level] = sl.tail
	}
	return
}

// findPredAtLevel finds the predecessor node at a specific level for the given key.
func (sl *SkipList[K, V]) findPredAtLevel(key K, level int) *node[K, V] {
	pred := sl.head
	curr := pred.next[level]
	for sl.nodeLessKey(curr, key) {
		pred = curr
		curr = pred.next[level]
	}
	return pred
}

// Find returns the value associated with the key, or the zero value and false if not found.
func (sl *SkipList[K, V]) Find(key K) (V, bool) {
	_, succs := sl.find(key)
	curr := succs[0]
	if curr != nil && nodeKeyIs(curr, key) && !curr.marked.Load() {
		return curr.value, true
	}
	var zero V
	return zero, false
}

// Upsert atomically updates or inserts a value.
// The check function is called while the relevant node (or predecessor) is locked.
// Returns (true, nil) if a node was updated, (false, nil) if inserted,
// or (_, err) if the check function returned an error.
func (sl *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (bool, error) {
	for {
		preds, succs := sl.find(key)
		curr := succs[0]

		if curr != nil && nodeKeyIs(curr, key) && !curr.marked.Load() {
			// Node exists — lock and update
			curr.mu.Lock()
			if curr.marked.Load() {
				// Being concurrently deleted, retry
				curr.mu.Unlock()
				continue
			}
			newVal, err := check(key, curr.value, true)
			if err != nil {
				curr.mu.Unlock()
				return true, err
			}
			curr.value = newVal
			curr.mu.Unlock()
			return true, nil
		}

		// Node doesn't exist — insert
		level := randomLevel()

		// Lock the bottom-level predecessor to atomically insert at level 0
		pred0 := preds[0]
		pred0.mu.Lock()

		// Validate: pred0 still points to succs[0] and isn't marked
		if pred0.next[0] != succs[0] || pred0.marked.Load() {
			pred0.mu.Unlock()
			continue // retry
		}

		// Also check if the key appeared concurrently
		if curr := succs[0]; curr != nil && nodeKeyIs(curr, key) && !curr.marked.Load() {
			pred0.mu.Unlock()
			continue // retry, key now exists
		}

		// Call check while holding pred0's lock
		var zeroV V
		newVal, err := check(key, zeroV, false)
		if err != nil {
			pred0.mu.Unlock()
			return false, err
		}

		// Create new node and link at level 0
		newNode := &node[K, V]{
			key:      key,
			value:    newVal,
			topLevel: level,
		}
		newNode.next[0] = succs[0]
		pred0.next[0] = newNode
		pred0.mu.Unlock()

		// Link at higher levels
		for i := 1; i <= level; i++ {
			if newNode.marked.Load() {
				break // node is being deleted, stop
			}
			for {
				pred := sl.findPredAtLevel(key, i)
				pred.mu.Lock()
				if pred.marked.Load() {
					pred.mu.Unlock()
					continue
				}
				newNode.next[i] = pred.next[i]
				pred.next[i] = newNode
				pred.mu.Unlock()
				break
			}
		}

		// Update max level
		sl.mu.Lock()
		if level > sl.topLevel {
			sl.topLevel = level
		}
		sl.mu.Unlock()

		return false, nil
	}
}

// Remove removes the key from the skip list.
// Returns the removed value and true if found, or zero value and false otherwise.
func (sl *SkipList[K, V]) Remove(key K) (V, bool) {
	_, succs := sl.find(key)
	curr := succs[0]

	if curr == nil || !nodeKeyIs(curr, key) || curr.marked.Load() {
		var zero V
		return zero, false
	}

	// Logical deletion: mark the node
	curr.mu.Lock()
	if curr.marked.Load() {
		curr.mu.Unlock()
		var zero V
		return zero, false
	}
	curr.marked.Store(true)
	value := curr.value
	curr.mu.Unlock()

	// Physical deletion: unlink at all levels (top to bottom)
	sl.mu.Lock()
	topLevel := sl.topLevel
	sl.mu.Unlock()

	for level := topLevel; level >= 0; level-- {
		pred := sl.findPredAtLevel(key, level)
		pred.mu.Lock()
		// curr may have been moved past by concurrent inserts, find it again
		next := pred.next[level]
		for next != sl.tail && sl.nodeLessKey(next, key) {
			pred.mu.Unlock()
			pred = next
			pred.mu.Lock()
			next = pred.next[level]
		}
		if next == curr {
			pred.next[level] = curr.next[level]
		}
		pred.mu.Unlock()
	}

	return value, true
}

// Query returns all pairs with keys in [start, end] (inclusive).
// The ctx parameter allows cancellation of long-running queries.
func (sl *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	// Navigate to the first node >= start
	pred := sl.head
	curr := pred.next[0]
	for !curr.isTail && curr.key < start {
		pred = curr
		curr = pred.next[0]
	}

	// Collect nodes with keys <= end
	for !curr.isTail && curr.key <= end {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

// QueryAll returns all pairs in the skip list in key order.
func (sl *SkipList[K, V]) QueryAll(ctx context.Context) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	curr := sl.head.next[0]
	for !curr.isTail {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

// QueryFrom returns all pairs with keys >= start in key order.
func (sl *SkipList[K, V]) QueryFrom(ctx context.Context, start K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	// Navigate to first node >= start
	pred := sl.head
	curr := pred.next[0]
	for !curr.isTail && curr.key < start {
		pred = curr
		curr = pred.next[0]
	}

	for !curr.isTail {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

// QueryTo returns all pairs with keys <= end in key order.
func (sl *SkipList[K, V]) QueryTo(ctx context.Context, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	curr := sl.head.next[0]
	for !curr.isTail && curr.key <= end {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}
		if !curr.marked.Load() {
			results = append(results, Pair[K, V]{Key: curr.key, Value: curr.value})
		}
		curr = curr.next[0]
	}

	return results, nil
}

package main

import (
	"context"
	"errors"
	"fmt"
	"owldb/skiplist"
)

// DocMeta holds metadata for a document.
type DocMeta struct {
	CreatedBy      string  `json:"createdBy"`
	CreatedAt      int64   `json:"createdAt"`
	LastModifiedBy string  `json:"lastModifiedBy"`
	LastModifiedAt int64   `json:"lastModifiedAt"`
}

// Document holds the raw JSON content and metadata for a stored document.
type Document struct {
	Content []byte
	Meta    DocMeta
	// Collections associated with this document (key = collection name)
	Collections *skiplist.SkipList[string, *Collection]
}

// Collection holds the documents indexed by name.
type Collection struct {
	Name string
	Docs *skiplist.SkipList[string, *Document]
}

// DBStore is the top-level store holding all databases.
type DBStore struct {
	databases *skiplist.SkipList[string, *Collection]
}

// NewDBStore creates a new empty DBStore.
func NewDBStore() *DBStore {
	return &DBStore{
		databases: skiplist.New[string, *Collection](),
	}
}

// newDocument creates a new Document with the given content and metadata.
func newDocument(content []byte, meta DocMeta) *Document {
	return &Document{
		Content:     content,
		Meta:        meta,
		Collections: skiplist.New[string, *Collection](),
	}
}

// newCollection creates a new empty Collection with the given name.
func newCollection(name string) *Collection {
	return &Collection{
		Name: name,
		Docs: skiplist.New[string, *Document](),
	}
}

// ErrExists is returned when trying to create a resource that already exists.
var ErrExists = errors.New("already exists")

// ErrNotFound is returned when a resource is not found.
var ErrNotFound = errors.New("not found")

// ErrNoOverwrite is returned when a PUT with nooverwrite mode would overwrite.
var ErrNoOverwrite = errors.New("document already exists (nooverwrite mode)")

// CreateDatabase creates a new database with the given name.
// Returns ErrExists if the database already exists.
func (store *DBStore) CreateDatabase(name string) error {
	_, err := store.databases.Upsert(name, func(k string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			return curr, ErrExists
		}
		return newCollection(k), nil
	})
	return err
}

// DeleteDatabase removes a database by name.
// Returns ErrNotFound if the database doesn't exist.
func (store *DBStore) DeleteDatabase(name string) (*Collection, error) {
	db, found := store.databases.Remove(name)
	if !found {
		return nil, ErrNotFound
	}
	return db, nil
}

// GetDatabase returns the collection for a database by name.
func (store *DBStore) GetDatabase(name string) (*Collection, bool) {
	return store.databases.Find(name)
}

// parsedPath holds a parsed URL path segments.
type parsedPath struct {
	segments    []string
	hasTrailing bool
}

// isDatabase returns true if this path refers to a database (only one segment).
func (p parsedPath) isDatabase() bool {
	return len(p.segments) == 1 && p.hasTrailing
}

// isCollection returns true if this path refers to a collection.
func (p parsedPath) isCollection() bool {
	return p.hasTrailing && len(p.segments) >= 3
}

// isDocument returns true if this path refers to a document.
func (p parsedPath) isDocument() bool {
	return !p.hasTrailing && len(p.segments) >= 2
}

// dbName returns the database name.
func (p parsedPath) dbName() string {
	if len(p.segments) > 0 {
		return p.segments[0]
	}
	return ""
}

// navigateToCollection navigates through the database hierarchy to find the target collection.
// The collection is the container that holds the target document or collection.
// For a path like /db/doc1/col1/doc2/col2/, returns the col2 Collection.
// For a path like /db/doc1/, returns the database's root collection "db".
// For a path like /db/, returns the database collection itself.
func (store *DBStore) navigateToParentCollection(p parsedPath) (*Collection, string, error) {
	segs := p.segments

	if len(segs) == 0 {
		return nil, "", ErrNotFound
	}

	// Get the database
	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return nil, "", ErrNotFound
	}

	if len(segs) == 1 {
		// It's the database itself
		return dbCol, segs[0], nil
	}

	// Navigate through doc/col pairs
	// segs[0] = db name
	// segs[1] = doc name in db
	// segs[2] = collection name in doc
	// segs[3] = doc name in collection
	// etc.
	currentCol := dbCol
	i := 1
	for i < len(segs)-1 {
		docName := segs[i]
		doc, found := currentCol.Docs.Find(docName)
		if !found {
			return nil, "", ErrNotFound
		}
		i++
		if i >= len(segs)-1 {
			// Next is the target
			break
		}
		colName := segs[i]
		col, found := doc.Collections.Find(colName)
		if !found {
			return nil, "", ErrNotFound
		}
		currentCol = col
		i++
	}

	// At this point, currentCol is the parent collection and segs[len-1] is the target name
	return currentCol, segs[len(segs)-1], nil
}

// navigateToDocument navigates to find a document by its parsed path.
func (store *DBStore) navigateToDocument(p parsedPath) (*Document, *Collection, string, error) {
	if !p.isDocument() {
		return nil, nil, "", fmt.Errorf("path is not a document")
	}

	parentCol, docName, err := store.navigateToParentCollection(p)
	if err != nil {
		return nil, nil, "", err
	}

	doc, found := parentCol.Docs.Find(docName)
	if !found {
		return nil, nil, "", ErrNotFound
	}

	return doc, parentCol, docName, nil
}

// navigateToCollection navigates to find a collection by its parsed path.
func (store *DBStore) navigateToCollection(p parsedPath) (*Collection, error) {
	if p.isDatabase() {
		db, found := store.databases.Find(p.dbName())
		if !found {
			return nil, ErrNotFound
		}
		return db, nil
	}

	if !p.isCollection() {
		return nil, fmt.Errorf("path is not a collection")
	}

	segs := p.segments
	// For a collection path like /db/doc/col/, segs = ["db", "doc", "col"]
	// We need to navigate to the document that owns this collection

	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return nil, ErrNotFound
	}

	if len(segs) < 3 {
		return nil, ErrNotFound
	}

	// Navigate to the owning document, then find the collection
	currentCol := dbCol
	i := 1
	for i < len(segs)-1 {
		docName := segs[i]
		doc, found := currentCol.Docs.Find(docName)
		if !found {
			return nil, ErrNotFound
		}
		i++
		if i >= len(segs) {
			break
		}
		colName := segs[i]
		if i == len(segs)-1 {
			// This is the target collection
			col, found := doc.Collections.Find(colName)
			if !found {
				return nil, ErrNotFound
			}
			return col, nil
		}
		col, found := doc.Collections.Find(colName)
		if !found {
			return nil, ErrNotFound
		}
		currentCol = col
		i++
	}

	return nil, ErrNotFound
}

// getQueryCollection returns the Collection for a GET/subscribe query.
// Works for both database paths (/db/) and collection paths (/db/doc/col/).
func (store *DBStore) getQueryCollection(p parsedPath) (*Collection, error) {
	return store.navigateToCollection(p)
}

// PutDocument creates or updates a document at the given path.
// The check function is called to determine the new document content.
// Returns (true, doc, nil) if updated, (false, doc, nil) if created.
func (store *DBStore) PutDocument(p parsedPath, content []byte, meta DocMeta, noOverwrite bool) (updated bool, doc *Document, err error) {
	if !p.isDocument() {
		return false, nil, fmt.Errorf("path is not a document")
	}

	segs := p.segments
	if len(segs) == 0 {
		return false, nil, ErrNotFound
	}

	// Get the database
	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return false, nil, ErrNotFound
	}

	// Navigate to the parent collection
	// For path /db/doc, we PUT into dbCol directly
	// For path /db/doc1/col/doc2, navigate to col then put
	parentCol, err := store.getParentCollectionForPut(segs, dbCol)
	if err != nil {
		return false, nil, err
	}

	docName := segs[len(segs)-1]
	var resultDoc *Document

	updated, err = parentCol.Docs.Upsert(docName, func(k string, curr *Document, exists bool) (*Document, error) {
		if exists && noOverwrite {
			return curr, ErrNoOverwrite
		}
		var newMeta DocMeta
		if exists {
			// Keep original createdBy and createdAt
			newMeta = DocMeta{
				CreatedBy:      curr.Meta.CreatedBy,
				CreatedAt:      curr.Meta.CreatedAt,
				LastModifiedBy: meta.LastModifiedBy,
				LastModifiedAt: meta.LastModifiedAt,
			}
		} else {
			newMeta = meta
		}
		d := &Document{
			Content:     content,
			Meta:        newMeta,
			Collections: skiplist.New[string, *Collection](),
		}
		if exists {
			// Preserve existing collections
			d.Collections = curr.Collections
		}
		resultDoc = d
		return d, nil
	})
	if err != nil {
		return false, nil, err
	}

	return updated, resultDoc, nil
}

// getParentCollectionForPut navigates to the parent collection for a PUT operation.
func (store *DBStore) getParentCollectionForPut(segs []string, dbCol *Collection) (*Collection, error) {
	if len(segs) <= 2 {
		// Document directly in database
		return dbCol, nil
	}

	// Navigate through doc/col/doc/col pairs
	// segs[0] = db, segs[1..n-2] = alternating doc/col, segs[n-1] = target doc
	currentCol := dbCol
	i := 1
	for i < len(segs)-1 {
		docName := segs[i]
		doc, found := currentCol.Docs.Find(docName)
		if !found {
			return nil, ErrNotFound
		}
		i++
		if i >= len(segs)-1 {
			break
		}
		colName := segs[i]
		col, found := doc.Collections.Find(colName)
		if !found {
			return nil, ErrNotFound
		}
		currentCol = col
		i++
	}
	return currentCol, nil
}

// DeleteDocument removes a document at the given path.
// Returns the deleted document, ErrNotFound if it doesn't exist.
func (store *DBStore) DeleteDocument(p parsedPath) (*Document, error) {
	if !p.isDocument() {
		return nil, fmt.Errorf("path is not a document")
	}

	segs := p.segments
	if len(segs) == 0 {
		return nil, ErrNotFound
	}

	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return nil, ErrNotFound
	}

	parentCol, err := store.getParentCollectionForPut(segs, dbCol)
	if err != nil {
		return nil, err
	}

	docName := segs[len(segs)-1]
	doc, removed := parentCol.Docs.Remove(docName)
	if !removed {
		return nil, ErrNotFound
	}
	return doc, nil
}

// CreateCollection creates a collection at the given path.
// For a path like /db/doc/col/, creates "col" under doc.
// For a path like /db/, creates the database (handled by CreateDatabase).
func (store *DBStore) CreateCollection(p parsedPath) error {
	if p.isDatabase() {
		return store.CreateDatabase(p.dbName())
	}

	if !p.isCollection() {
		return fmt.Errorf("path is not a collection")
	}

	segs := p.segments
	// segs = ["db", "doc", "col"] for /db/doc/col/
	// We need to navigate to the document owning the collection

	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return ErrNotFound
	}

	// Navigate to the parent document
	currentCol := dbCol
	i := 1
	for i < len(segs)-1 {
		docName := segs[i]
		doc, found := currentCol.Docs.Find(docName)
		if !found {
			return ErrNotFound
		}
		i++
		if i >= len(segs)-1 {
			// This doc owns the target collection
			colName := segs[i]
			_, err := doc.Collections.Upsert(colName, func(k string, curr *Collection, exists bool) (*Collection, error) {
				if exists {
					return curr, ErrExists
				}
				return newCollection(k), nil
			})
			return err
		}
		colName := segs[i]
		col, found := doc.Collections.Find(colName)
		if !found {
			return ErrNotFound
		}
		currentCol = col
		i++
	}

	return ErrNotFound
}

// DeleteCollection removes a collection at the given path.
func (store *DBStore) DeleteCollection(p parsedPath) (*Collection, error) {
	if p.isDatabase() {
		return store.DeleteDatabase(p.dbName())
	}

	if !p.isCollection() {
		return nil, fmt.Errorf("path is not a collection")
	}

	segs := p.segments
	// segs = ["db", "doc", "col"] for /db/doc/col/

	dbCol, found := store.databases.Find(segs[0])
	if !found {
		return nil, ErrNotFound
	}

	currentCol := dbCol
	i := 1
	for i < len(segs)-1 {
		docName := segs[i]
		doc, found := currentCol.Docs.Find(docName)
		if !found {
			return nil, ErrNotFound
		}
		i++
		if i >= len(segs)-1 {
			colName := segs[i]
			col, removed := doc.Collections.Remove(colName)
			if !removed {
				return nil, ErrNotFound
			}
			return col, nil
		}
		colName := segs[i]
		col, found := doc.Collections.Find(colName)
		if !found {
			return nil, ErrNotFound
		}
		currentCol = col
		i++
	}

	return nil, ErrNotFound
}

// QueryCollection returns all documents in a collection with optional interval filtering.
// interval = "" returns all documents.
// interval = "[low,high]" returns documents with keys >= low and <= high.
// interval = "[low,]" returns documents with keys >= low.
// interval = "[,high]" returns documents with keys <= high.
func QueryCollection(ctx context.Context, col *Collection, low string, high string, hasLow bool, hasHigh bool) ([]skiplist.Pair[string, *Document], error) {
	if !hasLow && !hasHigh {
		return col.Docs.QueryAll(ctx)
	} else if hasLow && !hasHigh {
		return col.Docs.QueryFrom(ctx, low)
	} else if !hasLow && hasHigh {
		return col.Docs.QueryTo(ctx, high)
	}
	return col.Docs.Query(ctx, low, high)
}

package main

import (
	"crypto/rand"
	"encoding/base64"
	"encoding/json"
	"errors"
	"os"
	"sync"
	"time"
)

const tokenExpiry = time.Hour

// tokenEntry holds a token's username and expiration time.
type tokenEntry struct {
	username  string
	expiresAt time.Time
}

// AuthManager manages authentication tokens.
type AuthManager struct {
	mu     sync.RWMutex
	tokens map[string]tokenEntry
}

// NewAuthManager creates a new AuthManager.
func NewAuthManager() *AuthManager {
	return &AuthManager{
		tokens: make(map[string]tokenEntry),
	}
}

// generateToken creates a new random token string.
func generateToken() (string, error) {
	b := make([]byte, 18)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(b), nil
}

// Login authenticates a user and returns a new bearer token.
func (am *AuthManager) Login(username string) (string, error) {
	token, err := generateToken()
	if err != nil {
		return "", err
	}
	am.mu.Lock()
	defer am.mu.Unlock()
	am.tokens[token] = tokenEntry{
		username:  username,
		expiresAt: time.Now().Add(tokenExpiry),
	}
	return token, nil
}

// Logout invalidates the given bearer token.
// Returns an error if the token is not found or already expired.
func (am *AuthManager) Logout(token string) error {
	am.mu.Lock()
	defer am.mu.Unlock()
	entry, ok := am.tokens[token]
	if !ok || time.Now().After(entry.expiresAt) {
		return errors.New("missing or invalid bearer token")
	}
	delete(am.tokens, token)
	return nil
}

// Validate checks if the token is valid and not expired.
// Returns the username associated with the token, or an error.
func (am *AuthManager) Validate(token string) (string, error) {
	am.mu.RLock()
	entry, ok := am.tokens[token]
	am.mu.RUnlock()
	if !ok {
		return "", errors.New("missing or invalid bearer token")
	}
	if time.Now().After(entry.expiresAt) {
		am.mu.Lock()
		delete(am.tokens, token)
		am.mu.Unlock()
		return "", errors.New("token has expired")
	}
	return entry.username, nil
}

// LoadTokenFile loads pre-configured tokens from a JSON file.
// The file format is: {"username": "token", ...}
// Loaded tokens are given a 24+ hour expiry.
func (am *AuthManager) LoadTokenFile(path string) error {
	data, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	var tokenMap map[string]string
	if err := json.Unmarshal(data, &tokenMap); err != nil {
		return err
	}
	am.mu.Lock()
	defer am.mu.Unlock()
	// Tokens expire 25 hours from now (effectively never for testing)
	expiry := time.Now().Add(25 * time.Hour)
	for username, token := range tokenMap {
		am.tokens[token] = tokenEntry{
			username:  username,
			expiresAt: expiry,
		}
	}
	return nil
}

package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"
)

// sseEvent is a server-sent event.
type sseEvent struct {
	Event string
	Data  string
	ID    int64
}

// subscriber holds the channel and filter for a single SSE subscriber.
type subscriber struct {
	ch       chan sseEvent
	path     string // the subscribed path (without /v1/ prefix)
	isDoc    bool   // true if subscribed to a document, false if collection
	interval *queryInterval
}

// queryInterval holds optional interval bounds for collection subscriptions.
type queryInterval struct {
	hasLow  bool
	low     string
	hasHigh bool
	high    string
}

// SubscriptionManager manages SSE subscribers.
type SubscriptionManager struct {
	mu          sync.RWMutex
	subscribers map[string][]*subscriber // key = normalized path
}

// NewSubscriptionManager creates a new SubscriptionManager.
func NewSubscriptionManager() *SubscriptionManager {
	return &SubscriptionManager{
		subscribers: make(map[string][]*subscriber),
	}
}

// subscribe registers a new subscriber for the given path.
// isDoc should be true if subscribing to a document, false for a collection.
func (sm *SubscriptionManager) subscribe(path string, isDoc bool, interval *queryInterval) *subscriber {
	sub := &subscriber{
		ch:       make(chan sseEvent, 100),
		path:     path,
		isDoc:    isDoc,
		interval: interval,
	}
	sm.mu.Lock()
	sm.subscribers[path] = append(sm.subscribers[path], sub)
	sm.mu.Unlock()
	return sub
}

// unsubscribe removes a subscriber.
func (sm *SubscriptionManager) unsubscribe(path string, sub *subscriber) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	subs := sm.subscribers[path]
	for i, s := range subs {
		if s == sub {
			sm.subscribers[path] = append(subs[:i], subs[i+1:]...)
			break
		}
	}
	if len(sm.subscribers[path]) == 0 {
		delete(sm.subscribers, path)
	}
}

// notifyDocumentUpdate sends an update event to all subscribers watching the given document.
// docPath is the full path like "db/doc" or "db/doc/col/doc2".
func (sm *SubscriptionManager) notifyDocumentUpdate(docPath string, content []byte, meta DocMeta) {
	now := time.Now().UnixMilli()

	// Build the event data
	var docJSON json.RawMessage = content
	metaMap := map[string]interface{}{
		"createdBy":      meta.CreatedBy,
		"createdAt":      meta.CreatedAt,
		"lastModifiedBy": meta.LastModifiedBy,
		"lastModifiedAt": meta.LastModifiedAt,
	}
	metaJSON, _ := json.Marshal(metaMap)

	updateData := map[string]json.RawMessage{
		"path": mustMarshalJSON("/" + docPath),
		"doc":  docJSON,
		"meta": metaJSON,
	}
	updateJSON, _ := json.Marshal(updateData)

	evt := sseEvent{
		Event: "update",
		Data:  string(updateJSON),
		ID:    now,
	}

	sm.mu.RLock()
	defer sm.mu.RUnlock()

	// Notify direct document subscribers
	for _, sub := range sm.subscribers[docPath] {
		select {
		case sub.ch <- evt:
		default:
		}
	}

	// Notify collection subscribers
	// Find the parent collection path
	parentPath, docName := splitDocumentPath(docPath)
	if parentPath != "" {
		for _, sub := range sm.subscribers[parentPath] {
			if !sub.isDoc {
				// Check interval if present
				if sub.interval != nil {
					if !matchesInterval(docName, sub.interval) {
						continue
					}
				}
				select {
				case sub.ch <- evt:
				default:
				}
			}
		}
	}
}

// notifyDocumentDelete sends a delete event to all subscribers watching the given document.
func (sm *SubscriptionManager) notifyDocumentDelete(docPath string, docName string) {
	now := time.Now().UnixMilli()

	data, _ := json.Marshal("/" + docPath)
	evt := sseEvent{
		Event: "delete",
		Data:  string(data),
		ID:    now,
	}

	sm.mu.RLock()
	defer sm.mu.RUnlock()

	// Notify direct document subscribers
	for _, sub := range sm.subscribers[docPath] {
		select {
		case sub.ch <- evt:
		default:
		}
	}

	// Notify collection subscribers
	parentPath, _ := splitDocumentPath(docPath)
	if parentPath != "" {
		for _, sub := range sm.subscribers[parentPath] {
			if !sub.isDoc {
				if sub.interval != nil {
					if !matchesInterval(docName, sub.interval) {
						continue
					}
				}
				select {
				case sub.ch <- evt:
				default:
				}
			}
		}
	}
}

// notifyCollectionDelete sends a delete event to all collection subscribers.
func (sm *SubscriptionManager) notifyCollectionDelete(colPath string) {
	now := time.Now().UnixMilli()

	data, _ := json.Marshal("/" + colPath + "/")
	evt := sseEvent{
		Event: "delete",
		Data:  string(data),
		ID:    now,
	}

	sm.mu.RLock()
	defer sm.mu.RUnlock()

	for _, sub := range sm.subscribers[colPath] {
		select {
		case sub.ch <- evt:
		default:
		}
	}
}

// serveSSE serves server-sent events to the client.
func (sm *SubscriptionManager) serveSSE(w http.ResponseWriter, r *http.Request, sub *subscriber, path string) {
	// Set SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}

	// Set up a keepalive ticker (every 15 seconds)
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	defer sm.unsubscribe(path, sub)

	for {
		select {
		case evt, ok := <-sub.ch:
			if !ok {
				return
			}
			fmt.Fprintf(w, "event: %s\ndata: %s\nid: %d\n\n", evt.Event, evt.Data, evt.ID)
			flusher.Flush()
		case <-ticker.C:
			// Send a comment to keep the connection alive
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		case <-r.Context().Done():
			return
		}
	}
}

// splitDocumentPath splits a document path into its parent collection path and document name.
// e.g., "db/col/doc" → ("db/col", "doc")
// e.g., "db/doc" → ("db", "doc")
func splitDocumentPath(docPath string) (string, string) {
	idx := strings.LastIndex(docPath, "/")
	if idx < 0 {
		return "", docPath
	}
	return docPath[:idx], docPath[idx+1:]
}

// matchesInterval checks if a document name falls within the given interval.
func matchesInterval(name string, iv *queryInterval) bool {
	if iv.hasLow && name < iv.low {
		return false
	}
	if iv.hasHigh && name > iv.high {
		return false
	}
	return true
}

// mustMarshalJSON marshals v to JSON, panicking on error (should never happen for strings).
func mustMarshalJSON(v interface{}) json.RawMessage {
	b, err := json.Marshal(v)
	if err != nil {
		panic(err)
	}
	return b
}

package main

import (
	"encoding/json"
	"fmt"
	"owldb/jsondata"
	"strings"
)

// PatchOp holds a single patch operation.
type PatchOp struct {
	Op    string          `json:"op"`
	Path  string          `json:"path"`
	Value json.RawMessage `json:"value"`
}

// patchResult holds the result of applying patches.
type patchResult struct {
	Failed  bool
	Message string
}

// applyPatches applies a list of patch operations to a JSON document.
// Returns the modified document bytes, a result struct, and any error.
// The patches are applied in order; if any fails, none are applied.
func applyPatches(content []byte, ops []PatchOp) ([]byte, patchResult, error) {
	if len(ops) == 0 {
		return content, patchResult{Failed: false, Message: "patch applied"}, nil
	}

	// Unmarshal the document
	var doc jsondata.JSONValue
	if err := json.Unmarshal(content, &doc); err != nil {
		return content, patchResult{Failed: true, Message: fmt.Sprintf("invalid document JSON: %v", err)}, nil
	}

	// Convert to mutable map[string]interface{} for patching
	rawAny, err := jsonToAny(doc)
	if err != nil {
		return content, patchResult{Failed: true, Message: fmt.Sprintf("cannot convert document: %v", err)}, nil
	}

	// Apply each patch operation in order
	for _, op := range ops {
		var value interface{}
		if err := json.Unmarshal(op.Value, &value); err != nil {
			return content, patchResult{Failed: true, Message: fmt.Sprintf("invalid patch value: %v", err)}, nil
		}

		var applyErr error
		switch op.Op {
		case "ArrayAdd":
			rawAny, applyErr = patchArrayAdd(rawAny, op.Path, value)
		case "ArrayRemove":
			rawAny, applyErr = patchArrayRemove(rawAny, op.Path, value)
		case "ObjectAdd":
			rawAny, applyErr = patchObjectAdd(rawAny, op.Path, value)
		default:
			applyErr = fmt.Errorf("unknown operation: %s", op.Op)
		}

		if applyErr != nil {
			return content, patchResult{Failed: true, Message: applyErr.Error()}, nil
		}
	}

	// Marshal back to JSON
	result, err := json.Marshal(rawAny)
	if err != nil {
		return content, patchResult{Failed: true, Message: fmt.Sprintf("failed to marshal result: %v", err)}, nil
	}

	return result, patchResult{Failed: false, Message: "patch applied"}, nil
}

// jsonToAny converts a JSONValue to its underlying interface{} representation.
type jsonToAnyVisitor struct{}

func (v jsonToAnyVisitor) Map(m map[string]jsondata.JSONValue) (interface{}, error) {
	result := make(map[string]interface{}, len(m))
	for k, val := range m {
		sub, err := jsondata.Accept[interface{}](val, jsonToAnyVisitor{})
		if err != nil {
			return nil, err
		}
		result[k] = sub
	}
	return result, nil
}

func (v jsonToAnyVisitor) Slice(s []jsondata.JSONValue) (interface{}, error) {
	result := make([]interface{}, len(s))
	for i, val := range s {
		sub, err := jsondata.Accept[interface{}](val, jsonToAnyVisitor{})
		if err != nil {
			return nil, err
		}
		result[i] = sub
	}
	return result, nil
}

func (v jsonToAnyVisitor) Bool(b bool) (interface{}, error)        { return b, nil }
func (v jsonToAnyVisitor) Float64(f float64) (interface{}, error)  { return f, nil }
func (v jsonToAnyVisitor) String(s string) (interface{}, error)    { return s, nil }
func (v jsonToAnyVisitor) Null() (interface{}, error)              { return nil, nil }

func jsonToAny(doc jsondata.JSONValue) (interface{}, error) {
	return jsondata.Accept[interface{}](doc, jsonToAnyVisitor{})
}

// parseJSONPointer splits a JSON Pointer (RFC 6901) into segments.
// "/a/b/c" → ["a", "b", "c"]
func parseJSONPointer(ptr string) ([]string, error) {
	if ptr == "" {
		return []string{}, nil
	}
	if !strings.HasPrefix(ptr, "/") {
		return nil, fmt.Errorf("json pointer must start with /")
	}
	parts := strings.Split(ptr[1:], "/")
	// Unescape ~1 (/) and ~0 (~)
	for i, p := range parts {
		p = strings.ReplaceAll(p, "~1", "/")
		p = strings.ReplaceAll(p, "~0", "~")
		parts[i] = p
	}
	return parts, nil
}

// navigateToParent navigates the document to the parent of the target path.
// Returns the parent object/array and the final key/index.
func navigateToParent(root interface{}, parts []string) (interface{}, string, error) {
	if len(parts) == 0 {
		return nil, "", fmt.Errorf("empty path")
	}
	if len(parts) == 1 {
		return root, parts[0], nil
	}

	current := root
	for _, part := range parts[:len(parts)-1] {
		switch c := current.(type) {
		case map[string]interface{}:
			val, ok := c[part]
			if !ok {
				return nil, "", fmt.Errorf("path not found: %s", part)
			}
			current = val
		default:
			return nil, "", fmt.Errorf("path element is not an object or array")
		}
	}
	return current, parts[len(parts)-1], nil
}

// patchArrayAdd adds a value to an array at the given JSON Pointer path.
func patchArrayAdd(root interface{}, ptr string, value interface{}) (interface{}, error) {
	parts, err := parseJSONPointer(ptr)
	if err != nil {
		return root, err
	}
	if len(parts) == 0 {
		return root, fmt.Errorf("path cannot be empty for ArrayAdd")
	}

	parent, key, err := navigateToParent(root, parts)
	if err != nil {
		return root, fmt.Errorf("invalid path: %v", err)
	}

	parentMap, ok := parent.(map[string]interface{})
	if !ok {
		return root, fmt.Errorf("parent is not an object")
	}

	arr, ok := parentMap[key]
	if !ok {
		return root, fmt.Errorf("path not found: %s", key)
	}

	arrSlice, ok := arr.([]interface{})
	if !ok {
		return root, fmt.Errorf("target is not an array")
	}

	// Check if value already exists (don't add duplicates)
	for _, v := range arrSlice {
		if jsonEqual(v, value) {
			// Already exists, no-op (not a failure)
			return root, nil
		}
	}

	parentMap[key] = append(arrSlice, value)
	return root, nil
}

// patchArrayRemove removes a value from an array at the given JSON Pointer path.
func patchArrayRemove(root interface{}, ptr string, value interface{}) (interface{}, error) {
	parts, err := parseJSONPointer(ptr)
	if err != nil {
		return root, err
	}
	if len(parts) == 0 {
		return root, fmt.Errorf("path cannot be empty for ArrayRemove")
	}

	parent, key, err := navigateToParent(root, parts)
	if err != nil {
		return root, fmt.Errorf("invalid path: %v", err)
	}

	parentMap, ok := parent.(map[string]interface{})
	if !ok {
		return root, fmt.Errorf("parent is not an object")
	}

	arr, ok := parentMap[key]
	if !ok {
		return root, fmt.Errorf("path not found: %s", key)
	}

	arrSlice, ok := arr.([]interface{})
	if !ok {
		return root, fmt.Errorf("target is not an array")
	}

	// Remove the value if it exists
	newSlice := make([]interface{}, 0, len(arrSlice))
	for _, v := range arrSlice {
		if !jsonEqual(v, value) {
			newSlice = append(newSlice, v)
		}
	}
	parentMap[key] = newSlice
	return root, nil
}

// patchObjectAdd adds a property to an object at the given JSON Pointer path.
// The last part of the path is the key to add; the parent must be an object.
// ObjectAdd only adds if the key doesn't already exist.
func patchObjectAdd(root interface{}, ptr string, value interface{}) (interface{}, error) {
	parts, err := parseJSONPointer(ptr)
	if err != nil {
		return root, err
	}
	if len(parts) == 0 {
		return root, fmt.Errorf("path cannot be empty for ObjectAdd")
	}

	// Navigate to parent (all parts except the last)
	var parent interface{}
	if len(parts) == 1 {
		parent = root
	} else {
		// Navigate to the parent of the key
		current := root
		for _, part := range parts[:len(parts)-1] {
			switch c := current.(type) {
			case map[string]interface{}:
				val, ok := c[part]
				if !ok {
					return root, fmt.Errorf("path not found: %s", part)
				}
				current = val
			default:
				return root, fmt.Errorf("path element is not an object")
			}
		}
		parent = current
	}

	parentMap, ok := parent.(map[string]interface{})
	if !ok {
		return root, fmt.Errorf("parent is not an object")
	}

	key := parts[len(parts)-1]
	if _, exists := parentMap[key]; exists {
		// Key already exists — ObjectAdd does not overwrite, but it's not a failure
		return root, nil
	}

	parentMap[key] = value
	return root, nil
}

// jsonEqual compares two JSON values for equality.
func jsonEqual(a, b interface{}) bool {
	// Marshal both to JSON and compare
	aBytes, aErr := json.Marshal(a)
	bBytes, bErr := json.Marshal(b)
	if aErr != nil || bErr != nil {
		return false
	}
	return string(aBytes) == string(bBytes)
}

package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"math/rand"
	"net/http"
	"owldb/jsondata"
	"strings"
	"time"

	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

// Server holds all dependencies for the HTTP server.
type Server struct {
	store   *DBStore
	auth    *AuthManager
	subs    *SubscriptionManager
	schema  *jsonschema.Schema
}

// NewServer creates a new Server.
func NewServer(schema *jsonschema.Schema) *Server {
	return &Server{
		store:  NewDBStore(),
		auth:   NewAuthManager(),
		subs:   NewSubscriptionManager(),
		schema: schema,
	}
}

// ServeHTTP implements the http.Handler interface.
func (s *Server) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Add CORS headers
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type")

	path := r.URL.Path

	if path == "/auth" || path == "/auth/" {
		s.handleAuth(w, r)
		return
	}

	if path == "/v1/" || path == "/v1" {
		// Root listing or OPTIONS
		if r.Method == http.MethodOptions {
			s.handleOptions(w, r, false)
			return
		}
		// Could list all databases — return empty array
		if r.Method == http.MethodGet {
			writeJSON(w, http.StatusOK, []interface{}{})
			return
		}
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
		return
	}

	if strings.HasPrefix(path, "/v1/") {
		s.handleV1(w, r)
		return
	}

	writeError(w, http.StatusNotFound, "not found")
}

// handleAuth handles POST /auth (login) and DELETE /auth (logout).
func (s *Server) handleAuth(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodPost:
		s.handleLogin(w, r)
	case http.MethodDelete:
		s.handleLogout(w, r)
	case http.MethodOptions:
		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
		w.WriteHeader(http.StatusOK)
	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

// handleLogin handles POST /auth.
func (s *Server) handleLogin(w http.ResponseWriter, r *http.Request) {
	var body struct {
		Username string `json:"username"`
	}
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil || body.Username == "" {
		writeError(w, http.StatusBadRequest, "no username in request body")
		return
	}

	token, err := s.auth.Login(body.Username)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to generate token")
		return
	}

	writeJSON(w, http.StatusOK, map[string]string{"token": token})
}

// handleLogout handles DELETE /auth.
func (s *Server) handleLogout(w http.ResponseWriter, r *http.Request) {
	token := extractBearerToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "missing or invalid bearer token")
		return
	}
	if err := s.auth.Logout(token); err != nil {
		writeError(w, http.StatusUnauthorized, err.Error())
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

// handleV1 handles all /v1/* requests.
func (s *Server) handleV1(w http.ResponseWriter, r *http.Request) {
	// OPTIONS doesn't require auth
	if r.Method == http.MethodOptions {
		s.handleOptions(w, r, true)
		return
	}

	// Validate auth for all other methods
	token := extractBearerToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "missing or invalid bearer token")
		return
	}
	username, err := s.auth.Validate(token)
	if err != nil {
		writeError(w, http.StatusUnauthorized, err.Error())
		return
	}

	// Parse the path
	rawPath := r.URL.Path[len("/v1/"):]
	p := parsePath(rawPath)

	if len(p.segments) == 0 {
		writeError(w, http.StatusBadRequest, "empty path")
		return
	}

	// Check for subscribe mode
	if r.URL.Query().Get("mode") == "subscribe" {
		s.handleSubscribe(w, r, p)
		return
	}

	switch r.Method {
	case http.MethodGet:
		s.handleGet(w, r, p)
	case http.MethodPut:
		s.handlePut(w, r, p, username)
	case http.MethodPost:
		s.handlePost(w, r, p, username)
	case http.MethodPatch:
		s.handlePatch(w, r, p, username)
	case http.MethodDelete:
		s.handleDelete(w, r, p)
	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

// handleOptions handles OPTIONS requests.
func (s *Server) handleOptions(w http.ResponseWriter, r *http.Request, isV1 bool) {
	if !isV1 {
		w.Header().Set("Allow", "GET, OPTIONS")
		w.WriteHeader(http.StatusOK)
		return
	}

	rawPath := r.URL.Path[len("/v1/"):]
	p := parsePath(rawPath)

	var allow string
	if p.isCollection() || p.isDatabase() {
		allow = "GET, PUT, POST, DELETE, OPTIONS"
	} else if p.isDocument() {
		allow = "GET, PUT, DELETE, PATCH, OPTIONS"
	} else {
		allow = "GET, PUT, POST, DELETE, PATCH, OPTIONS"
	}

	w.Header().Set("Allow", allow)
	w.WriteHeader(http.StatusOK)
}

// handleGet handles GET requests to /v1/*.
func (s *Server) handleGet(w http.ResponseWriter, r *http.Request, p parsedPath) {
	if p.isDatabase() || p.isCollection() {
		s.handleGetCollection(w, r, p)
	} else if p.isDocument() {
		s.handleGetDocument(w, r, p)
	} else {
		writeError(w, http.StatusBadRequest, "invalid path")
	}
}

// handleGetDocument returns a single document.
func (s *Server) handleGetDocument(w http.ResponseWriter, r *http.Request, p parsedPath) {
	doc, _, _, err := s.store.navigateToDocument(p)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeError(w, http.StatusNotFound, "document not found")
		} else {
			writeError(w, http.StatusNotFound, err.Error())
		}
		return
	}

	resp, err := buildDocumentResponse(p, doc)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to build response")
		return
	}
	writeJSON(w, http.StatusOK, resp)
}

// handleGetCollection returns documents in a collection.
func (s *Server) handleGetCollection(w http.ResponseWriter, r *http.Request, p parsedPath) {
	col, err := s.store.getQueryCollection(p)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeError(w, http.StatusNotFound, "collection not found")
		} else {
			writeError(w, http.StatusNotFound, err.Error())
		}
		return
	}

	// Parse interval query parameter
	low, high, hasLow, hasHigh := parseInterval(r.URL.Query().Get("interval"))

	ctx := r.Context()
	pairs, err := QueryCollection(ctx, col, low, high, hasLow, hasHigh)
	if err != nil {
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}

	result := make([]interface{}, 0, len(pairs))
	for _, pair := range pairs {
		// Build path for this doc
		docP := parsedPath{
			segments:    append(p.segments, pair.Key),
			hasTrailing: false,
		}
		resp, err := buildDocumentResponse(docP, pair.Value)
		if err != nil {
			continue
		}
		result = append(result, resp)
	}

	writeJSON(w, http.StatusOK, result)
}

// handlePut handles PUT requests.
func (s *Server) handlePut(w http.ResponseWriter, r *http.Request, p parsedPath, username string) {
	if p.isDatabase() || p.isCollection() {
		s.handlePutCollection(w, r, p)
	} else if p.isDocument() {
		s.handlePutDocument(w, r, p, username)
	} else {
		writeError(w, http.StatusBadRequest, "invalid path")
	}
}

// handlePutCollection creates a database or collection.
func (s *Server) handlePutCollection(w http.ResponseWriter, r *http.Request, p parsedPath) {
	var err error
	if p.isDatabase() {
		err = s.store.CreateDatabase(p.dbName())
	} else {
		err = s.store.CreateCollection(p)
	}

	if err != nil {
		if errors.Is(err, ErrExists) {
			writeError(w, http.StatusConflict, "already exists")
		} else if errors.Is(err, ErrNotFound) {
			writeError(w, http.StatusNotFound, "parent not found")
		} else {
			writeError(w, http.StatusBadRequest, err.Error())
		}
		return
	}

	uri := "/v1/" + strings.Join(p.segments, "/") + "/"
	w.Header().Set("Location", uri)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

// handlePutDocument creates or updates a document.
func (s *Server) handlePutDocument(w http.ResponseWriter, r *http.Request, p parsedPath, username string) {
	content, err := readBody(r)
	if err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid request body: %v", err))
		return
	}

	// Validate content is valid JSON
	if !json.Valid(content) {
		writeError(w, http.StatusBadRequest, "invalid JSON in request body")
		return
	}

	// Validate against schema
	if err := validateSchema(s.schema, content); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("schema validation failed: %v", err))
		return
	}

	mode := r.URL.Query().Get("mode")
	noOverwrite := mode == "nooverwrite"

	now := time.Now().UnixMilli()
	meta := DocMeta{
		CreatedBy:      username,
		CreatedAt:      now,
		LastModifiedBy: username,
		LastModifiedAt: now,
	}

	updated, doc, err := s.store.PutDocument(p, content, meta, noOverwrite)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeError(w, http.StatusNotFound, "parent collection not found")
		} else if errors.Is(err, ErrNoOverwrite) {
			writeError(w, http.StatusConflict, "document already exists")
		} else {
			writeError(w, http.StatusBadRequest, err.Error())
		}
		return
	}

	// Notify subscribers
	docPathStr := strings.Join(p.segments, "/")
	go s.subs.notifyDocumentUpdate(docPathStr, content, doc.Meta)

	uri := "/v1/" + strings.Join(p.segments, "/")
	w.Header().Set("Location", uri)
	statusCode := http.StatusCreated
	if updated {
		statusCode = http.StatusOK
	}
	writeJSON(w, statusCode, map[string]string{"uri": uri})
}

// handlePost handles POST requests (create document with generated ID).
func (s *Server) handlePost(w http.ResponseWriter, r *http.Request, p parsedPath, username string) {
	if !p.isDatabase() && !p.isCollection() {
		writeError(w, http.StatusMethodNotAllowed, "POST only allowed on collections")
		return
	}

	content, err := readBody(r)
	if err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid request body: %v", err))
		return
	}

	if !json.Valid(content) {
		writeError(w, http.StatusBadRequest, "invalid JSON in request body")
		return
	}

	if err := validateSchema(s.schema, content); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("schema validation failed: %v", err))
		return
	}

	// Verify the collection exists
	col, err := s.store.getQueryCollection(p)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeError(w, http.StatusNotFound, "collection not found")
		} else {
			writeError(w, http.StatusNotFound, err.Error())
		}
		return
	}
	_ = col

	// Generate a unique ID
	docID := generateDocID()

	// Build the new document path
	newSegs := make([]string, len(p.segments)+1)
	copy(newSegs, p.segments)
	newSegs[len(p.segments)] = docID
	newP := parsedPath{segments: newSegs, hasTrailing: false}

	now := time.Now().UnixMilli()
	meta := DocMeta{
		CreatedBy:      username,
		CreatedAt:      now,
		LastModifiedBy: username,
		LastModifiedAt: now,
	}

	_, doc, err := s.store.PutDocument(newP, content, meta, false)
	if err != nil {
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}

	// Notify subscribers
	docPathStr := strings.Join(newSegs, "/")
	go s.subs.notifyDocumentUpdate(docPathStr, content, doc.Meta)

	uri := "/v1/" + strings.Join(newSegs, "/")
	w.Header().Set("Location", uri)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

// handlePatch handles PATCH requests.
func (s *Server) handlePatch(w http.ResponseWriter, r *http.Request, p parsedPath, username string) {
	if !p.isDocument() {
		writeError(w, http.StatusMethodNotAllowed, "PATCH only allowed on documents")
		return
	}

	// Parse the patch operations from the body
	var ops []PatchOp
	if err := json.NewDecoder(r.Body).Decode(&ops); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid patch body: %v", err))
		return
	}

	uri := "/v1/" + strings.Join(p.segments, "/")

	// Find the document and apply patches atomically
	var patchRes patchResult
	var patchErr error

	segs := p.segments
	if len(segs) == 0 {
		writeError(w, http.StatusNotFound, "document not found")
		return
	}

	dbCol, found := s.store.databases.Find(segs[0])
	if !found {
		writeError(w, http.StatusNotFound, "document not found")
		return
	}

	parentCol, err := s.store.getParentCollectionForPut(segs, dbCol)
	if err != nil {
		writeError(w, http.StatusNotFound, "document not found")
		return
	}

	docName := segs[len(segs)-1]
	now := time.Now().UnixMilli()
	var updatedContent []byte
	var updatedMeta DocMeta

	_, patchErr = parentCol.Docs.Upsert(docName, func(k string, curr *Document, exists bool) (*Document, error) {
		if !exists {
			patchRes = patchResult{Failed: true, Message: "document not found"}
			return curr, ErrNotFound
		}

		newContent, res, err := applyPatches(curr.Content, ops)
		if err != nil {
			patchRes = patchResult{Failed: true, Message: err.Error()}
			return curr, nil // Don't update
		}
		patchRes = res

		if res.Failed {
			return curr, nil // Don't update on failure
		}

		// Validate the new content against schema
		if err := validateSchema(s.schema, newContent); err != nil {
			patchRes = patchResult{Failed: true, Message: fmt.Sprintf("schema validation failed: %v", err)}
			return curr, nil
		}

		newMeta := DocMeta{
			CreatedBy:      curr.Meta.CreatedBy,
			CreatedAt:      curr.Meta.CreatedAt,
			LastModifiedBy: username,
			LastModifiedAt: now,
		}
		updatedContent = newContent
		updatedMeta = newMeta

		return &Document{
			Content:     newContent,
			Meta:        newMeta,
			Collections: curr.Collections,
		}, nil
	})

	if patchErr != nil && errors.Is(patchErr, ErrNotFound) {
		writeError(w, http.StatusNotFound, "document not found")
		return
	}

	if !patchRes.Failed && updatedContent != nil {
		docPathStr := strings.Join(p.segments, "/")
		go s.subs.notifyDocumentUpdate(docPathStr, updatedContent, updatedMeta)
	}

	writeJSON(w, http.StatusOK, map[string]interface{}{
		"uri":         uri,
		"patchFailed": patchRes.Failed,
		"message":     patchRes.Message,
	})
}

// handleDelete handles DELETE requests.
func (s *Server) handleDelete(w http.ResponseWriter, r *http.Request, p parsedPath) {
	if p.isDatabase() {
		db, err := s.store.DeleteDatabase(p.dbName())
		if err != nil {
			if errors.Is(err, ErrNotFound) {
				writeError(w, http.StatusNotFound, "database not found")
			} else {
				writeError(w, http.StatusInternalServerError, err.Error())
			}
			return
		}
		_ = db
		go s.subs.notifyCollectionDelete(p.dbName())
		writeJSON(w, http.StatusOK, map[string]string{"uri": "/v1/" + p.dbName() + "/"})
	} else if p.isCollection() {
		_, err := s.store.DeleteCollection(p)
		if err != nil {
			if errors.Is(err, ErrNotFound) {
				writeError(w, http.StatusNotFound, "collection not found")
			} else {
				writeError(w, http.StatusInternalServerError, err.Error())
			}
			return
		}
		colPath := strings.Join(p.segments, "/")
		go s.subs.notifyCollectionDelete(colPath)
		writeJSON(w, http.StatusOK, map[string]string{"uri": "/v1/" + colPath + "/"})
	} else if p.isDocument() {
		doc, err := s.store.DeleteDocument(p)
		if err != nil {
			if errors.Is(err, ErrNotFound) {
				writeError(w, http.StatusNotFound, "document not found")
			} else {
				writeError(w, http.StatusInternalServerError, err.Error())
			}
			return
		}
		_ = doc
		docPath := strings.Join(p.segments, "/")
		docName := p.segments[len(p.segments)-1]
		go s.subs.notifyDocumentDelete(docPath, docName)
		writeJSON(w, http.StatusOK, map[string]string{"uri": "/v1/" + docPath})
	} else {
		writeError(w, http.StatusBadRequest, "invalid path")
	}
}

// handleSubscribe handles GET with ?mode=subscribe.
func (s *Server) handleSubscribe(w http.ResponseWriter, r *http.Request, p parsedPath) {
	// Check auth
	token := extractBearerToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "missing or invalid bearer token")
		return
	}
	if _, err := s.auth.Validate(token); err != nil {
		writeError(w, http.StatusUnauthorized, err.Error())
		return
	}

	isDoc := p.isDocument()
	path := strings.Join(p.segments, "/")

	// Parse interval for collection subscriptions
	var iv *queryInterval
	if !isDoc {
		intervalStr := r.URL.Query().Get("interval")
		if intervalStr != "" {
			low, high, hasLow, hasHigh := parseInterval(intervalStr)
			iv = &queryInterval{hasLow: hasLow, low: low, hasHigh: hasHigh, high: high}
		}
	}

	sub := s.subs.subscribe(path, isDoc, iv)

	// Send the initial state
	if isDoc {
		doc, _, _, err := s.store.navigateToDocument(p)
		if err == nil {
			resp, _ := buildDocumentResponse(p, doc)
			data, _ := json.Marshal(resp)
			// Send initial update event
			sub.ch <- sseEvent{
				Event: "update",
				Data:  string(data),
				ID:    time.Now().UnixMilli(),
			}
		}
	} else {
		col, err := s.store.getQueryCollection(p)
		if err == nil {
			ctx := context.Background()
			low, high, hasLow, hasHigh := "", "", false, false
			if iv != nil {
				low, high, hasLow, hasHigh = iv.low, iv.high, iv.hasLow, iv.hasHigh
			}
			pairs, _ := QueryCollection(ctx, col, low, high, hasLow, hasHigh)
			for _, pair := range pairs {
				docP := parsedPath{
					segments:    append(p.segments, pair.Key),
					hasTrailing: false,
				}
				resp, _ := buildDocumentResponse(docP, pair.Value)
				data, _ := json.Marshal(resp)
				sub.ch <- sseEvent{
					Event: "update",
					Data:  string(data),
					ID:    time.Now().UnixMilli(),
				}
			}
		}
	}

	s.subs.serveSSE(w, r, sub, path)
}

// parsePath parses a URL path (after /v1/) into a parsedPath.
func parsePath(rawPath string) parsedPath {
	hasTrailing := strings.HasSuffix(rawPath, "/")
	trimmed := strings.TrimSuffix(rawPath, "/")
	trimmed = strings.TrimPrefix(trimmed, "/")

	if trimmed == "" {
		return parsedPath{segments: []string{}, hasTrailing: hasTrailing}
	}

	segments := strings.Split(trimmed, "/")
	// Filter out empty segments
	result := make([]string, 0, len(segments))
	for _, s := range segments {
		if s != "" {
			result = append(result, s)
		}
	}
	return parsedPath{segments: result, hasTrailing: hasTrailing}
}

// extractBearerToken extracts the Bearer token from the Authorization header.
func extractBearerToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if !strings.HasPrefix(auth, "Bearer ") {
		return ""
	}
	return strings.TrimPrefix(auth, "Bearer ")
}

// writeJSON writes a JSON response with the given status code.
func writeJSON(w http.ResponseWriter, status int, v interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	if err := json.NewEncoder(w).Encode(v); err != nil {
		slog.Error("failed to write response", "error", err)
	}
}

// writeError writes a JSON error response.
func writeError(w http.ResponseWriter, status int, message string) {
	writeJSON(w, status, map[string]string{"error": message})
}

// readBody reads and validates the request body as JSON.
func readBody(r *http.Request) ([]byte, error) {
	if r.Body == nil {
		return []byte("null"), nil
	}

	var raw json.RawMessage
	if err := json.NewDecoder(r.Body).Decode(&raw); err != nil {
		return nil, err
	}
	return raw, nil
}

// validateSchema validates JSON content against the given schema.
func validateSchema(schema *jsonschema.Schema, content []byte) error {
	if schema == nil {
		return nil
	}
	var v interface{}
	if err := json.Unmarshal(content, &v); err != nil {
		return err
	}
	return schema.Validate(v)
}

// buildDocumentResponse builds the response object for a document GET.
func buildDocumentResponse(p parsedPath, doc *Document) (map[string]interface{}, error) {
	var docContent jsondata.JSONValue
	if err := json.Unmarshal(doc.Content, &docContent); err != nil {
		return nil, err
	}

	// Convert document content to map for response
	docMap, err := jsondata.Accept[interface{}](docContent, jsonToAnyVisitor{})
	if err != nil {
		return nil, err
	}

	path := "/v1/" + strings.Join(p.segments, "/")
	return map[string]interface{}{
		"path": path,
		"doc":  docMap,
		"meta": map[string]interface{}{
			"createdBy":      doc.Meta.CreatedBy,
			"createdAt":      doc.Meta.CreatedAt,
			"lastModifiedBy": doc.Meta.LastModifiedBy,
			"lastModifiedAt": doc.Meta.LastModifiedAt,
		},
	}, nil
}

// parseInterval parses the interval query parameter.
// Format: [low,high] where low and/or high may be empty.
// Returns low, high, hasLow, hasHigh.
func parseInterval(interval string) (string, string, bool, bool) {
	if interval == "" {
		return "", "", false, false
	}

	// Remove brackets
	interval = strings.TrimPrefix(interval, "[")
	interval = strings.TrimSuffix(interval, "]")

	parts := strings.SplitN(interval, ",", 2)
	if len(parts) != 2 {
		return "", "", false, false
	}

	low := parts[0]
	high := parts[1]
	return low, high, low != "", high != ""
}

// generateDocID generates a unique document ID for POST requests.
func generateDocID() string {
	const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, 16)
	for i := range b {
		b[i] = chars[rand.Intn(len(chars))]
	}
	return string(b)
}

// OwlDB is a RESTful NoSQL document database implemented in Go.
// It supports JSON documents with schema validation, authentication,
// server-sent events for subscriptions, and atomic patch operations.
package main

import (
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"

	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

func main() {
	var server http.Server
	var port int
	var err error

	// Parse command line flags
	portFlag := flag.Int("p", 3318, "Port to listen on")
	schemaFlag := flag.String("s", "", "JSON schema file for document validation (required)")
	tokenFlag := flag.String("t", "", "JSON token file with pre-configured tokens")
	flag.Parse()

	port = *portFlag

	if *schemaFlag == "" {
		fmt.Fprintf(os.Stderr, "error: -s <schema file> is required\n")
		os.Exit(1)
	}

	// Load schema
	compiler := jsonschema.NewCompiler()
	schema, err := compiler.Compile(*schemaFlag)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: failed to load schema %s: %v\n", *schemaFlag, err)
		os.Exit(1)
	}

	// Create the server
	owlServer := NewServer(schema)

	// Load pre-configured tokens if provided
	if *tokenFlag != "" {
		if err := owlServer.auth.LoadTokenFile(*tokenFlag); err != nil {
			fmt.Fprintf(os.Stderr, "error: failed to load token file %s: %v\n", *tokenFlag, err)
			os.Exit(1)
		}
		slog.Info("Loaded token file", "path", *tokenFlag)
	}

	// Set up HTTP server
	server = http.Server{
		Addr:    fmt.Sprintf(":%d", port),
		Handler: owlServer,
	}

	// The following code should go last and remain unchanged.
	// Note that you must actually initialize 'server' and 'port'
	// before this.  Note that the server is started below by
	// calling ListenAndServe.  You must not start the server
	// before this.

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

