func (sm *SubscriptionManager) serveSSE(w http.ResponseWriter, r *http.Request, sub *subscriber, path string) {
	// Set SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}
	// Flush immediately so the client sees the 200 response even if there's no data yet
	flusher.Flush()

